SELECT h.*, ste.site_nm AS site_nm, usr.user_nm AS chg_user_nm, cd_pct.code_label AS chg_type_cd_nm FROM odh_pay_chg_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id LEFT JOIN sy_user usr ON usr.user_id = h.chg_user_id LEFT JOIN sy_code cd_pct ON cd_pct.code_grp = 'PAYMENT_CHG_TYPE' AND cd_pct.code_value = h.chg_type_cd
ORDER BY h.pay_chg_hist_id ASC ORDER BY h.pay_chg_hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT h.*, ste.site_nm AS site_nm, usr.user_nm AS chg_user_nm, cd_pct.code_label AS chg_type_cd_nm FROM odh_pay_chg_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id LEFT JOIN sy_user usr ON usr.user_id = h.chg_user_id LEFT JOIN sy_code cd_pct ON cd_pct.code_grp = 'PAYMENT_CHG_TYPE' AND cd_pct.code_value = h.chg_type_cd
ORDER BY h.pay_chg_hist_id ASC ORDER BY h.pay_chg_hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}
